final:
module top_module (
    input [1:0] h,
    output reg not_s
);

    always @(*) begin
        case (h)
            2'b00: not_s = 1;
            2'b01: not_s = 0;
            2'b10: not_s = 0;
            2'b11: not_s = 1;
            default: not_s = 0; // Default case
        endcase
    end
endmodule
